{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/pet-market-operations-system/repo/petmarket/backend/src/main.ts", "content": "import 'reflect-metadata';
import { NestFactory } from '@nestjs/core';
import { ValidationPipe } from '@nestjs/common';
import { AppModule } from './app.module';
import { HttpExceptionFilter } from './common/filters/http-exception.filter';
import { ResponseInterceptor } from './common/interceptors/response.interceptor';
import { createWinstonLogger } from './common/logger/winston.logger';

async function bootstrap(): Promise<void> {
  const logger = createWinstonLogger();
  const app = await NestFactory.create(AppModule, { logger });

  app.enableCors({
    origin: process.env.FRONTEND_ORIGIN ?? 'http://localhost:3000',
    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization'],
    credentials: true,
  });

  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: true,
      transform: true,
    }),
  );

  app.useGlobalFilters(new HttpExceptionFilter());
  app.useGlobalInterceptors(new ResponseInterceptor());

  const port = parseInt(process.env.PORT ?? '3001', 10);
  await app.listen(port);
  logger.log(`Backend running on port ${port}`, 'Bootstrap');
}

bootstrap();
"}

