  Injectable,
  NotFoundException,
  BadRequestException,
  ForbiddenException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import {
  Settlement,
  SettlementStatus,
} from '../database/entities/settlement.entity';
import { AuditService } from '../audit/audit.service';

@Injectable()
export class SettlementsService {
  constructor(
    @InjectRepository(Settlement)
    private readonly settlementRepo: Repository<Settlement>,
    private readonly auditService: AuditService,
  ) {}

  async findAll(userId: string, role: string): Promise<Settlement[]> {
    if (role === 'vendor') {
      return this.settlementRepo.find({
        where: { vendorId: userId },
        order: { createdAt: 'DESC' },
      });
    }
    return this.settlementRepo.find({ order: { createdAt: 'DESC' } });
  }

  async approveStep1(
    id: string,
    reviewerId: string,
    role: string,
  ): Promise<Settlement> {
    if (role !== 'ops_reviewer' && role !== 'admin') {
      throw new ForbiddenException('Only ops_reviewer can perform step 1 approval');
    }

    const settlement = await this.settlementRepo.findOne({ where: { id } });
    if (!settlement) {
      throw new NotFoundException('Settlement not found');
    }
    if (settlement.status !== SettlementStatus.PENDING) {
      throw new BadRequestException(
        'Settlement must be in pending status for step 1 approval',
      );
    }

    const before = { ...settlement };
    settlement.status = SettlementStatus.REVIEWER_APPROVED;
    settlement.reviewerApprovedBy = reviewerId;
    settlement.reviewerApprovedAt = new Date();
    const saved = await this.settlementRepo.save(settlement);

    await this.auditService.log({
      action: 'settlement.approve_step1',
      actorId: reviewerId,
      entityType: 'settlement',
      entityId: id,
      before,
      after: saved,
    });

    return saved;
  }

  async approveStep2(
    id: string,
    financeId: string,
    role: string,
  ): Promise<Settlement> {
    if (role !== 'finance_admin' && role !== 'admin') {
      throw new ForbiddenException('Only finance_admin can perform step 2 approval');
    }

    const settlement = await this.settlementRepo.findOne({ where: { id } });
    if (!settlement) {
      throw new NotFoundException('Settlement not found');
    }
    if (settlement.status !== SettlementStatus.REVIEWER_APPROVED) {
      throw new BadRequestException(
        'Step 1 approval must be completed before step 2',
      );
    }

    const before = { ...settlement };
    settlement.status = SettlementStatus.FINANCE_APPROVED;
    settlement.financeApprovedBy = financeId;
    settlement.financeApprovedAt = new Date();
    const saved = await this.settlementRepo.save(settlement);

    await this.auditService.log({
      action: 'settlement.approve_step2',
      actorId: financeId,
      entityType: 'settlement',
      entityId: id,
      before,
      after: saved,
    });

    return saved;
  }
}
"}

