import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { CreditScore } from '../database/entities/credit-score.entity';

@Injectable()
export class CreditsService {
  constructor(
    @InjectRepository(CreditScore)
    private readonly creditRepo: Repository<CreditScore>,
  ) {}

  async getMyScore(userId: string): Promise<CreditScore> {
    const score = await this.creditRepo.findOne({
      where: { userId },
      order: { computedAt: 'DESC' },
    });

    if (!score) {
      const defaultScore = this.creditRepo.create({
        userId,
        score: 500,
        transactionSuccessRate: 0,
        disputeRate: 0,
        cancellationRate: 0,
      });
      return this.creditRepo.save(defaultScore);
    }

    return score;
  }

  async computeScore(userId: string): Promise<CreditScore> {
    const existing = await this.creditRepo.findOne({
      where: { userId },
      order: { computedAt: 'DESC' },
    });

    if (!existing) {
      throw new NotFoundException('No credit data for user');
    }

    const score =
      (existing.transactionSuccessRate * 0.5 -
        existing.disputeRate * 0.3 -
        existing.cancellationRate * 0.2) *
      1000;

    const clamped = Math.min(1000, Math.max(0, score));

    const updated = this.creditRepo.create({
      userId,
      score: clamped,
      transactionSuccessRate: existing.transactionSuccessRate,
      disputeRate: existing.disputeRate,
      cancellationRate: existing.cancellationRate,
    });

    return this.creditRepo.save(updated);
  }
}
"}

