  Injectable,
  BadRequestException,
  NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, In } from 'typeorm';
import {
  ExportJob,
  ExportJobStatus,
} from '../database/entities/export-job.entity';
import { IsString, IsOptional, IsObject } from 'class-validator';

export class CreateExportDto {
  @IsString()
  type: string;

  @IsOptional()
  @IsObject()
  params?: Record<string, unknown>;
}

const MAX_CONCURRENT_JOBS = 2;
const EXPIRY_DAYS = 7;

@Injectable()
export class ExportsService {
  constructor(
    @InjectRepository(ExportJob)
    private readonly exportRepo: Repository<ExportJob>,
  ) {}

  async createJob(requesterId: string, dto: CreateExportDto): Promise<ExportJob> {
    const runningCount = await this.exportRepo.count({
      where: { status: In([ExportJobStatus.QUEUED, ExportJobStatus.RUNNING]) },
    });

    if (runningCount >= MAX_CONCURRENT_JOBS) {
      throw new BadRequestException(
        'Maximum concurrent export jobs reached (limit: 2)',
      );
    }

    const expiresAt = new Date();
    expiresAt.setDate(expiresAt.getDate() + EXPIRY_DAYS);

    const job = this.exportRepo.create({
      requesterId,
      status: ExportJobStatus.QUEUED,
      params: { type: dto.type, ...(dto.params ?? {}) },
      expiresAt,
    });

    const saved = await this.exportRepo.save(job);

    setImmediate(() => this.processJob(saved.id).catch(() => null));

    return saved;
  }

  async getJobStatus(id: string, requesterId: string, role: string): Promise<ExportJob> {
    const job = await this.exportRepo.findOne({ where: { id } });
    if (!job) {
      throw new NotFoundException('Export job not found');
    }
    if (role !== 'admin' && job.requesterId !== requesterId) {
      throw new NotFoundException('Export job not found');
    }
    return job;
  }

  async findAll(requesterId: string, role: string): Promise<ExportJob[]> {
    if (role === 'admin') {
      return this.exportRepo.find({ order: { createdAt: 'DESC' } });
    }
    return this.exportRepo.find({
      where: { requesterId },
      order: { createdAt: 'DESC' },
    });
  }

  private async processJob(jobId: string): Promise<void> {
    await this.exportRepo.update(jobId, { status: ExportJobStatus.RUNNING });

    await new Promise((resolve) => setTimeout(resolve, 500));

    await this.exportRepo.update(jobId, {
      status: ExportJobStatus.DONE,
      filePath: `/exports/${jobId}.csv`,
    });
  }
}
"}

