@UseGuards(JwtAuthGuard, RolesGuard)
@Roles('admin')
export class ExportsController {
  constructor(private readonly exportsService: ExportsService) {}

  @Get()
  findAll(@Req() req: Request) {
    const user = (req as Request & { user: JwtPayload }).user;
    return this.exportsService.findAll(user.sub, user.role);
  }

  @Post()
  create(@Body() dto: CreateExportDto, @Req() req: Request) {
    const user = (req as Request & { user: JwtPayload }).user;
    return this.exportsService.createJob(user.sub, dto);
  }

  @Get(':id/status')
  getStatus(
    @Param('id', ParseUUIDPipe) id: string,
    @Req() req: Request,
  ) {
    const user = (req as Request & { user: JwtPayload }).user;
    return this.exportsService.getJobStatus(id, user.sub, user.role);
  }
}
"}

