import { useAuthStore } from '../store/auth.store';

interface NavItem {
  to: string;
  label: string;
  roles: string[];
}

const navItems: NavItem[] = [
  { to: '/dashboard', label: 'Dashboard', roles: ['shopper', 'vendor', 'admin', 'ops_reviewer', 'finance_admin'] },
  { to: '/listings', label: 'Listings', roles: ['shopper', 'vendor', 'admin'] },
  { to: '/conversations', label: 'Conversations', roles: ['shopper', 'vendor', 'admin'] },
  { to: '/admin/settlements', label: 'Settlements', roles: ['admin', 'ops_reviewer', 'finance_admin'] },
  { to: '/admin/config', label: 'Config', roles: ['admin'] },
  { to: '/admin/audit', label: 'Audit Logs', roles: ['admin'] },
  { to: '/admin/exports', label: 'Exports', roles: ['admin'] },
];

export default function Sidebar() {
  const { role, user, logout } = useAuthStore();

  const visible = navItems.filter(
    (item) => role && item.roles.includes(role),
  );

  return (
    <aside className="w-56 flex-shrink-0 bg-white border-r border-border flex flex-col">
      <div className="p-4 border-b border-border">
        <h1 className="text-lg font-bold text-primary">PetMarket</h1>
        {user && (
          <p className="text-xs text-muted-foreground mt-1">
            {user.username} &middot; <span className="capitalize">{role}</span>
          </p>
        )}
      </div>
      <nav className="flex-1 p-2 space-y-1">
        {visible.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            className={({ isActive }) =>
              `block px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                isActive
                  ? 'bg-primary text-primary-foreground'
                  : 'text-foreground hover:bg-accent hover:text-accent-foreground'
              }`
            }
          >
            {item.label}
          </NavLink>
        ))}
      </nav>
      <div className="p-4 border-t border-border">
        <button
          onClick={logout}
          className="w-full text-left text-sm text-muted-foreground hover:text-foreground transition-colors"
        >
          Sign out
        </button>
      </div>
    </aside>
  );
}
"}

