          <p className="text-4xl font-bold text-primary">{Math.round(Number(credit.score))}</p>
          <div className="text-xs text-muted-foreground grid grid-cols-3 gap-2 pt-2">
            <div>
              <span className="block font-medium">Success Rate</span>
              {(credit.transactionSuccessRate * 100).toFixed(1)}%
            </div>
            <div>
              <span className="block font-medium">Dispute Rate</span>
              {(credit.disputeRate * 100).toFixed(1)}%
            </div>
            <div>
              <span className="block font-medium">Cancellation Rate</span>
              {(credit.cancellationRate * 100).toFixed(1)}%
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
"}

