{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/pet-market-operations-system/repo/petmarket/frontend/src/pages/Listings.tsx", "content": "import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { listingsApi } from '../api';
import { useAuthStore } from '../store/auth.store';
import { toast } from '../components/Toaster';

const createSchema = z.object({
  title: z.string().min(2),
  description: z.string().min(10),
  breed: z.string().min(2),
  age: z.coerce.number().positive(),
  region: z.string().min(2),
  priceUsd: z.coerce.number().positive(),
});

type CreateForm = z.infer<typeof createSchema>;

export default function Listings() {
  const navigate = useNavigate();
  const { role } = useAuthStore();
  const qc = useQueryClient();
  const [showForm, setShowForm] = useState(false);
  const [page, setPage] = useState(1);

  const { data, isLoading, isError, refetch } = useQuery({
    queryKey: ['listings', page],
    queryFn: () => listingsApi.getAll({ page, limit: 20 }),
  });

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<CreateForm>({ resolver: zodResolver(createSchema) });

  const createMutation = useMutation({
    mutationFn: (body: CreateForm) => listingsApi.create(body),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['listings'] });
      toast('Listing created!', 'success');
      setShowForm(false);
      reset();
    },
    onError: () => toast('Failed to create listing', 'error'),
  });

  if (isLoading) {
    return (
      <div className="animate-pulse space-y-3">
        {Array.from({ length: 5 }).map((_, i) => (
          <div key={i} className="h-16 bg-muted rounded" />
        ))}
      </div>
    );
  }

  if (isError) {
    return (
      <div className="text-center py-12">
        <p className="text-muted-foreground mb-4">Failed to load listings.</p>
        <button onClick={() => refetch()} className="text-primary underline text-sm">
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold">Listings</h1>
        {(role === 'vendor' || role === 'admin') && (
          <button
            onClick={() => setShowForm(!showForm)}
            className="bg-primary text-primary-foreground px-4 py-2 rounded-md text-sm font-medium hover:bg-primary/90 transition-colors"
          >
            {showForm ? 'Cancel' : '+ New Listing'}
          </button>
        )}
      </div>

      {showForm && (
        <form
          onSubmit={handleSubmit((data) => createMutation.mutate(data))}
          className="bg-white border border-border rounded-lg p-6 space-y-4"
        >
          <h2 className="font-semibold">Create New Listing</h2>
          <div className="grid grid-cols-2 gap-4">
            {(['title', 'breed', 'region'] as const).map((field) => (
              <div key={field}>
                <label className="block text-sm font-medium mb-1 capitalize">{field}</label>
                <input
                  {...register(field)}
                  className="w-full border border-input rounded px-3 py-2 text-sm"
                />
                {errors[field] && (
                  <p className="text-destructive text-xs mt-1">{errors[field]?.message}</p>
                )}
              </div>
            ))}
            <div>
              <label className="block text-sm font-medium mb-1">Age (months)</label>
              <input
                type="number"
                {...register('age')}
                className="w-full border border-input rounded px-3 py-2 text-sm"
              />
              {errors.age && <p className="text-destructive text-xs mt-1">{errors.age.message}</p>}
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Price (USD)</label>
              <input
                type="number"
                step="0.01"
                {...register('priceUsd')}
                className="w-full border border-input rounded px-3 py-2 text-sm"
              />
              {errors.priceUsd && (
                <p className="text-destructive text-xs mt-1">{errors.priceUsd.message}</p>
              )}
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium mb-1">Description</label>
            <textarea
              {...register('description')}
              rows={3}
              className="w-full border border-input rounded px-3 py-2 text-sm"
            />
            {errors.description && (
              <p className="text-destructive text-xs mt-1">{errors.description.message}</p>
            )}
          </div>
          <button
            type="submit"
            disabled={createMutation.isPending}
            className="bg-primary text-primary-foreground px-4 py-2 rounded-md text-sm font-medium disabled:opacity-60"
          >
            {createMutation.isPending ? 'Creating…' : 'Create Listing'}
          </button>
        </form>
      )}

      <div className="space-y-3">
        {data?.items.map((listing) => (
          <div
            key={listing.id}
            onClick={() => navigate(`/listings/${listing.id}`)}
            className="bg-white border border-border rounded-lg p-4 cursor-pointer hover:border-primary transition-colors"
          >
            <div className="flex items-start justify-between">
              <div>
                <h3 className="font-semibold">{listing.title}</h3>
                <p className="text-sm text-muted-foreground">
                  {listing.breed} &middot; {listing.region} &middot; {listing.age} mo
                </p>
              </div>
              <div className="text-right">
                <p className="font-semibold">${Number(listing.priceUsd).toLocaleString()}</p>
                <span
                  className={`text-xs px-2 py-0.5 rounded-full ${
                    listing.status === 'active'
                      ? 'bg-green-100 text-green-700'
                      : 'bg-yellow-100 text-yellow-700'
                  }`}
                >
                  {listing.status}
                </span>
              </div>
            </div>
          </div>
        ))}
        {data?.items.length === 0 && (
          <p className="text-center text-muted-foreground py-12">No listings found.</p>
        )}
      </div>

      {data && data.totalPages > 1 && (
        <div className="flex items-center justify-center gap-4">
          <button
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            disabled={page === 1}
            className="text-sm text-primary disabled:opacity-40"
          >
            Previous
          </button>
          <span className="text-sm text-muted-foreground">
            Page {page} of {data.totalPages}
          </span>
          <button
            onClick={() => setPage((p) => Math.min(data.totalPages, p + 1))}
            disabled={page === data.totalPages}
            className="text-sm text-primary disabled:opacity-40"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
}
"}

