import { useQuery, useMutation } from '@tanstack/react-query';
import { listingsApi, conversationsApi } from '../api';
import { useAuthStore } from '../store/auth.store';
import { toast } from '../components/Toaster';

export default function ListingDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { role } = useAuthStore();

  const { data: listing, isLoading, isError, refetch } = useQuery({
    queryKey: ['listing', id],
    queryFn: () => listingsApi.getOne(id!),
    enabled: !!id,
  });

  const contactMutation = useMutation({
    mutationFn: () => conversationsApi.create(id!),
    onSuccess: (conv) => {
      toast('Conversation started!', 'success');
      navigate(`/conversations`);
      void conv;
    },
    onError: () => toast('Failed to start conversation', 'error'),
  });

  if (isLoading) {
    return (
      <div className="animate-pulse space-y-4">
        <div className="h-8 bg-muted rounded w-1/2" />
        <div className="h-48 bg-muted rounded" />
      </div>
    );
  }

  if (isError || !listing) {
    return (
      <div className="text-center py-12">
        <p className="text-muted-foreground mb-4">Listing not found.</p>
        <button onClick={() => refetch()} className="text-primary underline text-sm">
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6 max-w-2xl">
      <button
        onClick={() => navigate(-1)}
        className="text-sm text-primary hover:underline"
      >
        ← Back
      </button>

      <div className="bg-white border border-border rounded-lg p-6 space-y-4">
        <div className="flex items-start justify-between">
          <h1 className="text-2xl font-bold">{listing.title}</h1>
          <span
            className={`text-xs px-2 py-1 rounded-full ${
              listing.status === 'active'
                ? 'bg-green-100 text-green-700'
                : 'bg-yellow-100 text-yellow-700'
            }`}
          >
            {listing.status}
          </span>
        </div>

        <div className="grid grid-cols-3 gap-4 text-sm">
          <div>
            <p className="text-muted-foreground">Breed</p>
            <p className="font-medium">{listing.breed}</p>
          </div>
          <div>
            <p className="text-muted-foreground">Age</p>
            <p className="font-medium">{listing.age} months</p>
          </div>
          <div>
            <p className="text-muted-foreground">Region</p>
            <p className="font-medium">{listing.region}</p>
          </div>
        </div>

        <div>
          <p className="text-muted-foreground text-sm mb-1">Description</p>
          <p className="text-sm">{listing.description}</p>
        </div>

        <div className="flex items-center justify-between pt-2">
          <p className="text-2xl font-bold">${Number(listing.priceUsd).toLocaleString()}</p>
          {role === 'shopper' && (
            <button
              onClick={() => contactMutation.mutate()}
              disabled={contactMutation.isPending}
              className="bg-primary text-primary-foreground px-6 py-2 rounded-md text-sm font-medium disabled:opacity-60 hover:bg-primary/90 transition-colors"
            >
              {contactMutation.isPending ? 'Starting…' : 'Contact Vendor'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
"}

