import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { conversationsApi, type Message } from '../api';
import { useAuthStore } from '../store/auth.store';
import { toast } from '../components/Toaster';

export default function Conversations() {
  const { role } = useAuthStore();
  const qc = useQueryClient();
  const [activeId, setActiveId] = useState<string | null>(null);
  const [input, setInput] = useState('');

  const { data: convs, isLoading, isError, refetch } = useQuery({
    queryKey: ['conversations'],
    queryFn: conversationsApi.getAll,
  });

  const { data: messages, isLoading: msgsLoading } = useQuery({
    queryKey: ['messages', activeId],
    queryFn: () => conversationsApi.getMessages(activeId!),
    enabled: !!activeId,
    refetchInterval: 5000,
  });

  const sendMutation = useMutation({
    mutationFn: (content: string) =>
      conversationsApi.sendMessage(activeId!, { content, type: 'text' }),
    onSuccess: () => {
      setInput('');
      qc.invalidateQueries({ queryKey: ['messages', activeId] });
      toast('Message sent', 'success');
    },
    onError: () => toast('Failed to send message', 'error'),
  });

  if (isLoading) {
    return (
      <div className="animate-pulse space-y-3">
        {Array.from({ length: 4 }).map((_, i) => (
          <div key={i} className="h-14 bg-muted rounded" />
        ))}
      </div>
    );
  }

  if (isError) {
    return (
      <div className="text-center py-12">
        <p className="text-muted-foreground mb-4">Failed to load conversations.</p>
        <button onClick={() => refetch()} className="text-primary underline text-sm">
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="flex h-full gap-4">
      <aside className="w-64 flex-shrink-0 space-y-2">
        <h1 className="text-xl font-bold mb-4">Conversations</h1>
        {convs?.length === 0 && (
          <p className="text-sm text-muted-foreground">No conversations yet.</p>
        )}
        {convs?.map((c) => (
          <button
            key={c.id}
            onClick={() => setActiveId(c.id)}
            className={`w-full text-left p-3 rounded-lg border text-sm transition-colors ${
              activeId === c.id
                ? 'border-primary bg-primary/5'
                : 'border-border hover:border-primary/50'
            }`}
          >
            <p className="font-medium truncate">Listing #{c.listingId.slice(0, 8)}</p>
            <p className="text-xs text-muted-foreground mt-0.5">
              {new Date(c.createdAt).toLocaleDateString()}
            </p>
          </button>
        ))}
      </aside>

      <div className="flex-1 flex flex-col bg-white border border-border rounded-lg overflow-hidden">
        {!activeId ? (
          <div className="flex-1 flex items-center justify-center text-muted-foreground text-sm">
            Select a conversation
          </div>
        ) : (
          <>
            <div className="flex-1 overflow-y-auto p-4 space-y-3">
              {msgsLoading && (
                <div className="animate-pulse space-y-2">
                  {Array.from({ length: 3 }).map((_, i) => (
                    <div key={i} className="h-10 bg-muted rounded" />
                  ))}
                </div>
              )}
              {messages?.map((m: Message) => (
                <div
                  key={m.id}
                  className={`max-w-xs rounded-lg px-3 py-2 text-sm ${
                    m.isInternal
                      ? 'bg-yellow-50 border border-yellow-200 text-yellow-800 ml-auto'
                      : 'bg-muted'
                  }`}
                >
                  {m.content}
                  {m.isInternal && (
                    <span className="text-xs ml-2 text-yellow-600">[internal]</span>
                  )}
                </div>
              ))}
            </div>
            <div className="p-3 border-t border-border flex gap-2">
              <input
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && input.trim()) sendMutation.mutate(input.trim());
                }}
                placeholder="Type a message…"
                className="flex-1 border border-input rounded px-3 py-2 text-sm"
              />
              <button
                onClick={() => {
                  if (input.trim()) sendMutation.mutate(input.trim());
                }}
                disabled={sendMutation.isPending || !input.trim()}
                className="bg-primary text-primary-foreground px-4 py-2 rounded text-sm disabled:opacity-60"
              >
                {sendMutation.isPending ? '…' : 'Send'}
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
"}

