import { settlementsApi } from '../../api';
import { useAuthStore } from '../../store/auth.store';
import { toast } from '../../components/Toaster';

const STATUS_COLORS: Record<string, string> = {
  pending: 'bg-yellow-100 text-yellow-700',
  reviewer_approved: 'bg-blue-100 text-blue-700',
  finance_approved: 'bg-green-100 text-green-700',
  rejected: 'bg-red-100 text-red-700',
};

export default function AdminSettlements() {
  const { role } = useAuthStore();
  const qc = useQueryClient();

  const { data, isLoading, isError, refetch } = useQuery({
    queryKey: ['settlements'],
    queryFn: settlementsApi.getAll,
  });

  const step1Mutation = useMutation({
    mutationFn: (id: string) => settlementsApi.approveStep1(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['settlements'] });
      toast('Step 1 approved', 'success');
    },
    onError: () => toast('Failed to approve', 'error'),
  });

  const step2Mutation = useMutation({
    mutationFn: (id: string) => settlementsApi.approveStep2(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['settlements'] });
      toast('Step 2 approved — Settlement finalized', 'success');
    },
    onError: () => toast('Failed to approve', 'error'),
  });

  if (isLoading) {
    return (
      <div className="animate-pulse space-y-3">
        {Array.from({ length: 5 }).map((_, i) => (
          <div key={i} className="h-16 bg-muted rounded" />
        ))}
      </div>
    );
  }

  if (isError) {
    return (
      <div className="text-center py-12">
        <p className="text-muted-foreground mb-4">Failed to load settlements.</p>
        <button onClick={() => refetch()} className="text-primary underline text-sm">
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">Settlements</h1>

      <div className="space-y-3">
        {data?.length === 0 && (
          <p className="text-center text-muted-foreground py-12">No settlements found.</p>
        )}
        {data?.map((s) => (
          <div key={s.id} className="bg-white border border-border rounded-lg p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="font-semibold">{s.month}</p>
                <p className="text-sm text-muted-foreground">
                  Total: ${Number(s.totalCharges).toFixed(2)} &middot; Tax: $
                  {Number(s.taxAmount).toFixed(2)}
                </p>
              </div>
              <div className="flex items-center gap-3">
                <span
                  className={`text-xs px-2 py-1 rounded-full ${
                    STATUS_COLORS[s.status] ?? 'bg-muted text-muted-foreground'
                  }`}
                >
                  {s.status.replace('_', ' ')}
                </span>
                {s.status === 'pending' && (role === 'ops_reviewer' || role === 'admin') && (
                  <button
                    onClick={() => step1Mutation.mutate(s.id)}
                    disabled={step1Mutation.isPending}
                    className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded disabled:opacity-60"
                  >
                    Approve (Step 1)
                  </button>
                )}
                {s.status === 'reviewer_approved' &&
                  (role === 'finance_admin' || role === 'admin') && (
                    <button
                      onClick={() => step2Mutation.mutate(s.id)}
                      disabled={step2Mutation.isPending}
                      className="text-xs bg-green-600 text-white px-3 py-1.5 rounded disabled:opacity-60"
                    >
                      Approve (Step 2)
                    </button>
                  )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
"}

