      <h1 className="text-2xl font-bold">Data Exports</h1>

      <div className="bg-white border border-border rounded-lg p-6">
        <h2 className="font-semibold mb-3">Create New Export</h2>
        <div className="flex flex-wrap gap-2">
          {EXPORT_TYPES.map((type) => (
            <button
              key={type}
              onClick={() => createMutation.mutate(type)}
              disabled={createMutation.isPending}
              className="bg-primary text-primary-foreground px-4 py-2 rounded text-sm disabled:opacity-60 hover:bg-primary/90 transition-colors"
            >
              Export {type.replace('_', ' ')}
            </button>
          ))}
        </div>
        <p className="text-xs text-muted-foreground mt-3">
          Max 2 concurrent jobs. Files expire after 7 days.
        </p>
      </div>

      <div className="space-y-3">
        {data?.length === 0 && (
          <p className="text-center text-muted-foreground py-8">No export jobs yet.</p>
        )}
        {data?.map((job) => (
          <div key={job.id} className="bg-white border border-border rounded-lg p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="font-mono text-sm">{String(job.params.type ?? 'unknown')}</p>
                <p className="text-xs text-muted-foreground">
                  {new Date(job.createdAt).toLocaleString()}
                  {job.expiresAt && (
                    <span> &middot; Expires {new Date(job.expiresAt).toLocaleDateString()}</span>
                  )}
                </p>
              </div>
              <div className="flex items-center gap-2">
                <span
                  className={`text-xs px-2 py-1 rounded-full ${
