import {
  Injectable,
  UnauthorizedException,
  OnApplicationBootstrap,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, DataSource } from 'typeorm';
import { JwtService } from '@nestjs/jwt';
import * as bcrypt from 'bcrypt';
import { User } from '../database/entities/user.entity';
import { LoginDto } from './dto/login.dto';
import { logger } from '../common/logger/winston.logger';
import { runSeed } from '../database/seed';

@Injectable()
export class AuthService implements OnApplicationBootstrap {
  constructor(
    @InjectRepository(User)
    private readonly userRepo: Repository<User>,
    private readonly jwtService: JwtService,
    private readonly dataSource: DataSource,
  ) {}

  async onApplicationBootstrap(): Promise<void> {
    try {
      await runSeed(this.dataSource);
    } catch (err) {
      logger.error('Seed failed', String(err), 'AuthService');
    }
  }

  async login(
    dto: LoginDto,
    ip?: string,
  ): Promise<{ token: string; user: Partial<User> }> {
    const user = await this.userRepo.findOne({
      where: { username: dto.username, isActive: true },
    });

    if (!user) {
      logger.warn(`Login failed: unknown user ${dto.username}`, { context: 'Auth', ip });
      throw new UnauthorizedException('Invalid credentials');
    }

    const passwordValid = await bcrypt.compare(dto.password, user.passwordHash);
    if (!passwordValid) {
      logger.warn(`Login failed: bad password for ${dto.username}`, { context: 'Auth', ip });
      throw new UnauthorizedException('Invalid credentials');
    }

    await this.userRepo.update(user.id, { lastIp: ip ?? null });

    const payload = { sub: user.id, username: user.username, role: user.role };
    const token = this.jwtService.sign(payload);

    logger.info(`Login success: ${user.username} role=${user.role}`, {
      context: 'Auth',
      ip,
    });

    const { passwordHash: _ph, ...safeUser } = user;
    return { token, user: safeUser };
  }
}
