import { RateLimitEvent } from '../database/entities/rate-limit-event.entity';
import { CreateListingDto, ListingsQueryDto } from './dto/create-listing.dto';

interface PaginatedResult<T> {
  items: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

@Injectable()
export class ListingsService {
