  async findAll(query: ListingsQueryDto): Promise<PaginatedResult<Listing>> {
    const page = Math.max(1, query.page ?? 1);
    const limit = Math.min(100, Math.max(1, query.limit ?? 20));
    const skip = (page - 1) * limit;

    const qb = this.listingRepo
      .createQueryBuilder('l')
      .where('l.status = :status', { status: ListingStatus.ACTIVE })
      .orderBy('l.createdAt', 'DESC')
      .skip(skip)
      .take(limit);

    if (query.breed) {
      qb.andWhere('LOWER(l.breed) LIKE :breed', {
        breed: `%${query.breed.toLowerCase()}%`,
      });
    }
    if (query.region) {
      qb.andWhere('LOWER(l.region) LIKE :region', {
        region: `%${query.region.toLowerCase()}%`,
      });
    }
    if (query.minPrice !== undefined) {
      qb.andWhere('l.priceUsd >= :minPrice', { minPrice: query.minPrice });
    }
    if (query.maxPrice !== undefined) {
      qb.andWhere('l.priceUsd <= :maxPrice', { maxPrice: query.maxPrice });
    }

    const [items, total] = await qb.getManyAndCount();

    return {
      items,
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit),
    };
  }

  async findOne(id: string): Promise<Listing> {
    const listing = await this.listingRepo.findOne({
      where: { id },
      relations: ['vendor'],
    });
    if (!listing) {
      throw new NotFoundException('Listing not found');
    }
    return listing;
  }

  async create(vendorId: string, dto: CreateListingDto): Promise<Listing> {
    await this.enforceRateLimit(vendorId);

    const sensitiveWords = await this.wordRepo.find();
    const combined = `${dto.title} ${dto.description}`.toLowerCase();
    const flagged = sensitiveWords.some((sw) =>
      combined.includes(sw.word.toLowerCase()),
    );

    const listing = this.listingRepo.create({
      ...dto,
      vendorId,
      photos: dto.photos ?? [],
      status: flagged ? ListingStatus.PENDING_REVIEW : ListingStatus.ACTIVE,
      sensitiveWordFlagged: flagged,
    });

    const saved = await this.listingRepo.save(listing);

    const event = this.rateLimitRepo.create({
      userId: vendorId,
      action: 'create_listing',
    });
    await this.rateLimitRepo.save(event);

    return saved;
  }

  private async enforceRateLimit(vendorId: string): Promise<void> {
    const windowStart = new Date(Date.now() - this.RATE_LIMIT_WINDOW_MS);
    const count = await this.rateLimitRepo.count({
      where: {
        userId: vendorId,
        action: 'create_listing',
        createdAt: MoreThanOrEqual(windowStart),
      },
    });
    if (count >= this.RATE_LIMIT_MAX) {
      throw new TooManyRequestsException(
        'Rate limit exceeded: max 30 listings per hour',
      );
    }
  }
}
