15	@Injectable()
16	export class AuthService implements OnApplicationBootstrap {
17	  constructor(
18	    @InjectRepository(User)
19	    private readonly userRepo: Repository<User>,
20	    private readonly jwtService: JwtService,
21	    private readonly dataSource: DataSource,
22	  ) {}
23	
24	  async onApplicationBootstrap(): Promise<void> {
25	    try {
26	      await runSeed(this.dataSource);
27	    } catch (err) {
28	      logger.error('Seed failed', String(err), 'AuthService');
29	    }
30	  }
31	
32	  async login(
33	    dto: LoginDto,
34	    ip?: string,
35	  ): Promise<{ token: string; user: Partial<User> }> {
36	    const user = await this.userRepo.findOne({
37	      where: { username: dto.username, isActive: true },
38	    });
39	
40	    if (!user) {
41	      logger.warn(`Login failed: unknown user ${dto.username}`, { context: 'Auth', ip });
42	      throw new UnauthorizedException('Invalid credentials');
43	    }
44	
45	    const passwordValid = await bcrypt.compare(dto.password, user.passwordHash);
46	    if (!passwordValid) {
47	      logger.warn(`Login failed: bad password for ${dto.username}`, { context: 'Auth', ip });
48	      throw new UnauthorizedException('Invalid credentials');
49	    }
50	
51	    await this.userRepo.update(user.id, { lastIp: ip ?? null });
52	
53	    const payload = { sub: user.id, username: user.username, role: user.role };
54	    const token = this.jwtService.sign(payload);
55	
56	    logger.info(`Login success: ${user.username} role=${user.role}`, {
57	      context: 'Auth',
58	      ip,
59	    });
60	
61	    const { passwordHash: _ph, ...safeUser } = user;
62	    return { token, user: safeUser };
63	  }
64	}
