7	export interface AuditLogInput {
8	  action: string;
9	  actorId: string;
10	  entityType: string;
11	  entityId?: string;
12	  before?: Record<string, unknown> | null;
13	  after?: Record<string, unknown> | null;
14	  deviceFingerprint?: string;
15	  ip?: string;
