18	@Injectable()
19	export class AuditService {
20	  constructor(
21	    @InjectRepository(AuditLog)
22	    private readonly auditRepo: Repository<AuditLog>,
23	  ) {}
24	
25	  async log(input: AuditLogInput): Promise<AuditLog> {
26	    const latest = await this.auditRepo.findOne({
27	      where: {},
28	      order: { createdAt: 'DESC' },
29	    });
30	
31	    const prevHash = latest?.hash ?? null;
32	    const hashContent = JSON.stringify({
33	      action: input.action,
34	      actorId: input.actorId,
35	      entityType: input.entityType,
36	      entityId: input.entityId ?? null,
37	      before: input.before ?? null,
38	      after: input.after ?? null,
39	      prevHash,
40	      ts: new Date().toISOString(),
41	    });
42	    const hash = crypto.createHash('sha256').update(hashContent).digest('hex');
43	
44	    const entry = this.auditRepo.create({
45	      action: input.action,
46	      actorId: input.actorId,
47	      entityType: input.entityType,
48	      entityId: input.entityId ?? null,
49	      before: input.before ?? null,
50	      after: input.after ?? null,
51	      deviceFingerprint: input.deviceFingerprint ?? null,
52	      ip: input.ip ?? null,
53	      hash,
54	      prevHash,
55	    });
56	
57	    return this.auditRepo.save(entry);
58	  }
59	
60	  async findAll(page = 1, limit = 50): Promise<{ items: AuditLog[]; total: number }> {
61	    const [items, total] = await this.auditRepo.findAndCount({
62	      order: { createdAt: 'DESC' },
63	      skip: (page - 1) * limit,
64	      take: limit,
65	    });
66	    return { items, total };
67	  }
