1	import {
2	  Injectable,
3	  BadRequestException,
4	  NotFoundException,
5	} from '@nestjs/common';
6	import { InjectRepository } from '@nestjs/typeorm';
7	import { Repository, In } from 'typeorm';
8	import {
9	  ExportJob,
10	  ExportJobStatus,
11	} from '../database/entities/export-job.entity';
12	import { IsString, IsOptional, IsObject } from 'class-validator';
13	
14	export class CreateExportDto {
15	  @IsString()
16	  type: string;
17	
18	  @IsOptional()
19	  @IsObject()
20	  params?: Record<string, unknown>;
21	}
22	
23	const MAX_CONCURRENT_JOBS = 2;
24	const EXPIRY_DAYS = 7;
25	
26	@Injectable()
27	export class ExportsService {
28	  constructor(
29	    @InjectRepository(ExportJob)
30	    private readonly exportRepo: Repository<ExportJob>,
31	  ) {}
32	
33	  async createJob(requesterId: string, dto: CreateExportDto): Promise<ExportJob> {
34	    const runningCount = await this.exportRepo.count({
35	      where: { status: In([ExportJobStatus.QUEUED, ExportJobStatus.RUNNING]) },
36	    });
37	
38	    if (runningCount >= MAX_CONCURRENT_JOBS) {
39	      throw new BadRequestException(
40	        'Maximum concurrent export jobs reached (limit: 2)',
41	      );
42	    }
43	
44	    const expiresAt = new Date();
45	    expiresAt.setDate(expiresAt.getDate() + EXPIRY_DAYS);
46	
47	    const job = this.exportRepo.create({
48	      requesterId,
49	      status: ExportJobStatus.QUEUED,
50	      params: { type: dto.type, ...(dto.params ?? {}) },
51	      expiresAt,
52	    });
53	
54	    const saved = await this.exportRepo.save(job);
55	
56	    setImmediate(() => this.processJob(saved.id).catch(() => null));
57	
58	    return saved;
59	  }
60	
61	  async getJobStatus(id: string, requesterId: string, role: string): Promise<ExportJob> {
62	    const job = await this.exportRepo.findOne({ where: { id } });
63	    if (!job) {
64	      throw new NotFoundException('Export job not found');
65	    }
66	    if (role !== 'admin' && job.requesterId !== requesterId) {
67	      throw new NotFoundException('Export job not found');
68	    }
69	    return job;
70	  }
71	
72	  async findAll(requesterId: string, role: string): Promise<ExportJob[]> {
73	    if (role === 'admin') {
74	      return this.exportRepo.find({ order: { createdAt: 'DESC' } });
75	    }
76	    return this.exportRepo.find({
77	      where: { requesterId },
78	      order: { createdAt: 'DESC' },
79	    });
80	  }
81	
82	  private async processJob(jobId: string): Promise<void> {
83	    await this.exportRepo.update(jobId, { status: ExportJobStatus.RUNNING });
84	
85	    await new Promise((resolve) => setTimeout(resolve, 500));
86	
87	    await this.exportRepo.update(jobId, {
88	      status: ExportJobStatus.DONE,
89	      filePath: `/exports/${jobId}.csv`,
90	    });
91	  }
92	}
