import { cn } from '../lib/utils';

interface Column<T> {
  key: string;
  header: string;
  sortable?: boolean;
  render?: (row: T) => React.ReactNode;
  className?: string;
}

interface Props<T> {
  columns: Column<T>[];
  data: T[];
  total?: number;
  page?: number;
  totalPages?: number;
  onPageChange?: (page: number) => void;
  onSort?: (key: string, dir: 'ASC' | 'DESC') => void;
  onRowClick?: (row: T) => void;
  loading?: boolean;
  emptyMessage?: string;
}

export default function DataTable<T extends Record<string, unknown>>({
  columns,
  data,
  total,
  page = 1,
  totalPages = 1,
  onPageChange,
  onSort,
  onRowClick,
  loading,
  emptyMessage = 'No data found',
}: Props<T>) {
