53	    const hash = crypto.createHash('sha256').update(hashPayload).digest('hex');
54	
55	    const entry = this.auditRepo.create({
56	      action: input.action,
57	      actorId: input.actorId,
58	      entityType: input.entityType,
59	      entityId: input.entityId ?? null,
60	      before: input.before ?? null,
61	      after: input.after ?? null,
62	      deviceFingerprint: input.deviceFingerprint ?? null,
63	      ip: input.ip ?? null,
64	      hash,
65	      prevHash,
66	    });
67	
68	    return this.auditRepo.save(entry);
69	  }
70	
71	  async findAll(
72	    page = 1,
73	    limit = 50,
74	  ): Promise<{ items: AuditLog[]; total: number }> {
75	    const [items, total] = await this.auditRepo.findAndCount({
76	      order: { createdAt: 'DESC' },
77	      skip: (page - 1) * limit,
78	      take: limit,
79	    });
80	    return { items, total };
81	  }
82	
83	  async findAllFiltered(
84	    filters: AuditFilters,
85	  ): Promise<{ items: (AuditLog & { actorUsername?: string })[]; total: number }> {
86	    const page = Math.max(1, filters.page ?? 1);
87	    const limit = Math.min(200, Math.max(1, filters.limit ?? 50));
88	
89	    const qb = this.auditRepo
90	      .createQueryBuilder('a')
91	      .orderBy('a.createdAt', 'DESC');
92	
93	    if (filters.actorId) {
94	      qb.andWhere('a.actorId = :actorId', { actorId: filters.actorId });
95	    }
96	    if (filters.entityType) {
97	      qb.andWhere('a.entityType = :entityType', { entityType: filters.entityType });
98	    }
99	    if (filters.action) {
100	      qb.andWhere('a.action ILIKE :action', { action: `%${filters.action}%` });
101	    }
102	    if (filters.startDate) {
103	      qb.andWhere('a.createdAt >= :startDate', { startDate: new Date(filters.startDate) });
104	    }
105	    if (filters.endDate) {
106	      qb.andWhere('a.createdAt <= :endDate', { endDate: new Date(filters.endDate) });
107	    }
108	    if (filters.keyword) {
109	      qb.andWhere(
110	        '(CAST(a.before AS text) ILIKE :kw OR CAST(a.after AS text) ILIKE :kw)',
111	        { kw: `%${filters.keyword}%` },
112	      );
113	    }
114	
115	    qb.skip((page - 1) * limit).take(limit);
116	
117	    const [items, total] = await qb.getManyAndCount();
118	
119	    const actorIds = [...new Set(items.map((i) => i.actorId).filter(Boolean))];
120	    const userMap: Record<string, string> = {};
121	    if (actorIds.length > 0) {
122	      const userRepo = this.auditRepo.manager.getRepository(User);
123	      const users = await userRepo
124	        .createQueryBuilder('u')
125	        .where('u.id IN (:...ids)', { ids: actorIds })
126	        .getMany();
127	      for (const u of users) {
128	        userMap[u.id] = u.username;
129	      }
130	    }
131	
132	    const enriched = items.map((item) => ({
133	      ...item,
134	      actorUsername: userMap[item.actorId] ?? 'unknown',
135	    }));
136	
137	    return { items: enriched, total };
138	  }
139	
140	  async verifyEntry(id: string): Promise<{ valid: boolean; entry: AuditLog }> {
141	    const entry = await this.auditRepo.findOne({ where: { id } });
142	    if (!entry) {
143	      throw new Error('Audit entry not found');
144	    }
145	
146	    const recomputedPayload = (entry.prevHash ?? '') + JSON.stringify({
147	      action: entry.action,
148	      actorId: entry.actorId,
149	      entityType: entry.entityType,
150	      entityId: entry.entityId ?? null,
151	      before: entry.before ?? null,
152	      after: entry.after ?? null,
153	      ts: entry.createdAt.toISOString(),
154	    });
155	    const recomputedHash = crypto
156	      .createHash('sha256')
157	      .update(recomputedPayload)
158	      .digest('hex');
159	
160	    return {
161	      valid: recomputedHash === entry.hash,
162	      entry,
163	    };
164	  }
165	}
