113	          <span className="text-xs text-gray-500">
114	            {total !== undefined ? `${total} results` : `Page ${page}`}
115	          </span>
116	          <div className="flex items-center gap-2">
117	            <button
118	              onClick={() => onPageChange?.(page - 1)}
119	              disabled={page <= 1}
120	              className="px-3 py-1 text-xs rounded border border-gray-300 disabled:opacity-40 hover:bg-white"
121	            >
122	              Previous
123	            </button>
124	            <span className="text-xs text-gray-600">
125	              {page} / {totalPages}
126	            </span>
127	            <button
128	              onClick={() => onPageChange?.(page + 1)}
129	              disabled={page >= totalPages}
130	              className="px-3 py-1 text-xs rounded border border-gray-300 disabled:opacity-40 hover:bg-white"
131	            >
132	              Next
133	            </button>
134	          </div>
135	        </div>
136	      )}
137	    </div>
138	  );
139	}
